import React, { useState, useEffect, useRef } from "react";
import { io } from "socket.io-client";
import CallWindow from "./CallWindow";

const socket = io("http://localhost:3001");

export default function ChatPage({ currentUser, friend, onBack }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [showCall, setShowCall] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [status, setStatus] = useState({ online: false, lastSeen: null });
  const chatBoxRef = useRef();
  let typingTimeout;

  // Load history + mark read
  useEffect(() => {
    const loadHistory = async () => {
      const res = await fetch(`http://localhost:3001/chat/${currentUser.userId}/${friend.userId}`);
      const data = await res.json();
      setMessages(data.map(c => ({
        senderId: c.senderId,
        message: c.message,
        createdAt: c.createdAt,
        status: c.status
      })));
    };
    loadHistory();

    socket.emit("mark read", { userA: currentUser.userId, userB: friend.userId });
  }, [currentUser, friend]);

  // Socket listeners
  useEffect(() => {
    socket.emit("register user", currentUser.userId);

    socket.on("chat message", (data) => {
      if (data.senderId === friend.userId || data.senderId === currentUser.userId) {
        setMessages(prev => [...prev, data]);
      }
    });

    socket.on("messages read", () => {
      setMessages(prev => prev.map(m => ({ ...m, status: "read" })));
    });

    socket.on("typing", ({ fromId }) => {
      if (fromId === friend.userId) setIsTyping(true);
    });
    socket.on("stop typing", ({ fromId }) => {
      if (fromId === friend.userId) setIsTyping(false);
    });

    socket.on("status update", ({ userId, online, lastSeen }) => {
      if (userId === friend.userId) setStatus({ online, lastSeen });
    });

    return () => {
      socket.off("chat message");
      socket.off("messages read");
      socket.off("typing");
      socket.off("stop typing");
      socket.off("status update");
    };
  }, [friend, currentUser]);

  useEffect(() => {
    chatBoxRef.current?.scrollTo(0, chatBoxRef.current.scrollHeight);
  }, [messages]);

  // Send message
  const sendMessage = () => {
    if (!input.trim()) return;
    socket.emit("chat message", {
      senderId: currentUser.userId,
      receiverId: friend.userId,
      message: input
    });
    setInput("");
    socket.emit("stop typing", { fromId: currentUser.userId, toId: friend.userId });
  };

  // Typing handler
  const handleTyping = (e) => {
    setInput(e.target.value);
    socket.emit("typing", { fromId: currentUser.userId, toId: friend.userId });
    clearTimeout(typingTimeout);
    typingTimeout = setTimeout(() => {
      socket.emit("stop typing", { fromId: currentUser.userId, toId: friend.userId });
    }, 2000);
  };

  // Helpers
  const formatTime = (isoString) => {
    const date = new Date(isoString);
    return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  };

  const renderTicks = (status) => {
    if (status === "sent") return "✓";
    if (status === "delivered") return "✓✓";
    if (status === "read") return <span style={{ color: "blue" }}>✓✓</span>;
    return "";
  };

  const formatLastSeen = (dateString) => {
    if (!dateString) return "";
    const date = new Date(dateString);
    return `last seen ${date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}`;
  };

  // UI
  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100vh" }}>
      {/* Header */}
      <div style={{ background: "#075E54", color: "white", padding: "15px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div>
          <button onClick={onBack} style={{ marginRight: "10px", background: "transparent", border: "none", color: "white", fontSize: "18px" }}>←</button>
          <h3 style={{ margin: 0 }}>{friend.userId}</h3>
          <div style={{ fontSize: "12px", color: "#ddd" }}>
            {status.online ? "online" : formatLastSeen(status.lastSeen)}
          </div>
        </div>
        <button onClick={() => setShowCall(true)} style={{ background: "transparent", border: "none", color: "white", fontSize: "18px" }}>
          📹
        </button>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: "auto", padding: "10px", background: "#e5ddd5" }} ref={chatBoxRef}>
        {messages.map((msg, i) => (
          <div
            key={i}
            style={{
              maxWidth: "70%",
              margin: "5px 0",
              padding: "10px",
              borderRadius: "10px",
              background: msg.senderId === currentUser.userId ? "#dcf8c6" : "#fff",
              alignSelf: msg.senderId === currentUser.userId ? "flex-end" : "flex-start",
              boxShadow: "0 1px 1px rgba(0,0,0,0.2)"
            }}
          >
            {msg.message}
            <div style={{ fontSize: "10px", textAlign: "right", marginTop: "5px", color: "#555" }}>
              {msg.createdAt ? formatTime(msg.createdAt) : ""}
              {msg.senderId === currentUser.userId && (
                <span style={{ marginLeft: "5px" }}>{renderTicks(msg.status)}</span>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div style={{ fontStyle: "italic", color: "#555", marginTop: "5px" }}>
            {friend.userId} is typing…
          </div>
        )}
      </div>

      {/* Input */}
      <div style={{ display: "flex", padding: "10px", background: "#f0f0f0" }}>
        <input
          value={input}
          onChange={handleTyping}
          placeholder="Type a message"
          style={{ flex: 1, padding: "10px", borderRadius: "20px", border: "1px solid #ccc" }}
        />
        <button onClick={sendMessage} style={{ marginLeft: "10px", padding: "10px 20px", borderRadius: "20px", background: "#25d366", color: "white", border: "none" }}>
          Send
        </button>
      </div>

      {/* Call Overlay */}
      {showCall && (
        <CallWindow
          currentUser={currentUser}
          friend={friend}
          onHangUp={() => setShowCall(false)}
        />
      )}
    </div>
  );
}
